#!/usr/bin/env bash
set -euo pipefail;source "$(dirname "$0")/lib/android-test.sh";serial=;package=org.archphene.linux.p0392be9c9f103a39d951c2f39c3644d2;while (($#));do case "$1" in --serial)serial="${2:?}";shift 2;;--package)package="${2:?}";shift 2;;*)archphene_die "unknown argument: $1";;esac;done;[[ -n "$serial" ]] || archphene_die '--serial required';archphene_test_init "$serial";activity="$(archphene_launcher "$package")";old_acc="$(archphene_adb_run shell settings get system accelerometer_rotation|tr -d '\r')";old_rot="$(archphene_adb_run shell settings get system user_rotation|tr -d '\r')";trap 'archphene_adb_run shell settings put system accelerometer_rotation "$old_acc" >/dev/null;archphene_adb_run shell settings put system user_rotation "$old_rot" >/dev/null' EXIT;archphene_adb_run shell settings put system accelerometer_rotation 0;archphene_adb_run shell settings put system user_rotation 0;archphene_adb_run shell am start -W -n "$activity" >/dev/null;sleep 8;pid="$(archphene_android_pid "$package")";child="$(archphene_linux_loader_pid "$pid")";portrait="$(archphene_capture_ui kcalc-portrait)";archphene_adb_run shell settings put system user_rotation 1;sleep 4;landscape="$(archphene_capture_ui kcalc-landscape)";pid2="$(archphene_android_pid "$package")";child2="$(archphene_linux_loader_pid "$pid2")";[[ "$pid" == "$pid2" && "$child" == "$child2" ]] || archphene_die 'KCalc restarted during rotation';[[ "$portrait" != "$landscape" ]] || archphene_die 'viewport did not change';archphene_note "KCalc live rotation passed on $serial: Android PID $pid, Linux PID $child."
